              fontSize: 20,
              color: Colors.white,
              fontWeight: FontWeight.bold,
            ),
          ), //子组件显示的文本
        ),
        IconButton(
          onPressed: () {
            widget.onDelete(widget.index); //调用回调函数删除当前子组件
          },
          icon: Icon(Icons.delete, color: Colors.cyanAccent, size: 30),
        ), //删除按钮,点击删除子组件
      ],
    );
  }
}
