然后我们编辑配置文件,这里我做了一些改动,使用阿里云百炼的deepseek的v4 pro模型

```JavaScript
const CONFIG = {
  // 你的 阿里云百炼 (DashScope) API Key
  // 请在 Cloudflare Worker 的环境变量中设置，或者直接填在这里（不推荐直接暴露）
  ALIYUN_API_KEY: 'sk-xxxxxxxxxx',

  // 阿里云百炼 OpenAI 兼容 API 端点
  API_URL: 'https://dashscope.aliyuncs.com/compatible-mode/v1/chat/completions',

  // 强制使用的模型名称
  TARGET_MODEL: 'deepseek-v4-pro',

  // 允许的域名白名单
  ALLOWED_ORIGINS: [
    'https://funingna-wakawaka.github.io', // 你的 GitHub Pages 域名
    // 注意！仅在本地测试时添加 localhost
    // 'http://localhost:4000' 
  ],

  // 速率限制配置 (可选)
  RATE_LIMIT: {
    enabled: true,
    maxRequests: 100,  // 每个 IP 每小时最多请求次数
    windowMs: 3600000  // 1小时
  }
};

// 速率限制存储 (注意：在免费版 Worker 中，全局变量可能会在不同的请求间重置。如需严格限制，建议改用 Cloudflare KV)
const rateLimitMap = new Map();

addEventListener('fetch', event => {
  const request = event.request;

  // 处理 OPTIONS 预检请求 (CORS)
  if (request.method === 'OPTIONS') {
    event.respondWith(handleOptions(request));
  } else {
    event.respondWith(handleRequest(request));
  }
});

function handleOptions(request) {
  const origin = request.headers.get('Origin');

  // 验证来源
  if (origin && isOriginAllowed(origin, null)) {
    return new Response(null, {
      status: 204,
      headers: {
        'Access-Control-Allow-Origin': origin,
        'Access-Control-Allow-Methods': 'POST, OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type, Authorization',
        'Access-Control-Max-Age': '86400'
      }
    });
  }

  return new Response(null, { status: 403 });
}

async function handleRequest(request) {
  // 只允许 POST 请求
  if (request.method !== 'POST') {
    return new Response('Method not allowed', { status: 405 });
  }

  // 获取请求来源
  const origin = request.headers.get('Origin');
  const referer = request.headers.get('Referer');

  console.log('Request from:', origin || referer);

  // 验证域名白名单
  if (!isOriginAllowed(origin, referer)) {
    console.log('Origin not allowed');
    return new Response(JSON.stringify({
      error: 'Forbidden',
      message: 'Domain not in whitelist',
      origin: origin,
      referer: referer
    }), {
      status: 403,
      headers: { 
        'Content-Type': 'application/json',
        'Access-Control-Allow-Origin': origin || '*'
      }
    });
  }

  // 速率限制检查
  const clientIP = request.headers.get('CF-Connecting-IP') || 'unknown';
  if (CONFIG.RATE_LIMIT.enabled && !checkRateLimit(clientIP)) {
    return new Response(JSON.stringify({
      error: 'Rate limit exceeded',
      message: 'Too many requests. Please try again later.'
    }), {
      status: 429,
      headers: { 
        'Content-Type': 'application/json',
        'Retry-After': '3600',
        'Access-Control-Allow-Origin': origin || '*'
      }
    });
  }

  try {
    // 获取前端传来的请求体
    const requestBody = await request.json();
    console.log('Request body received');

    // 验证并修改请求参数
    if (!validateAndFormatRequest(requestBody)) {
      return new Response(JSON.stringify({
        error: 'Invalid request',
        message: 'Request body validation failed: missing messages'
      }), {
        status: 400,
        headers: { 
          'Content-Type': 'application/json',
          'Access-Control-Allow-Origin': origin || '*'
        }
      });
    }

    // 转发请求到阿里云 API
    const apiResponse = await fetch(CONFIG.API_URL, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${CONFIG.ALIYUN_API_KEY}`
      },
      body: JSON.stringify(requestBody)
    });

    console.log('API Response status:', apiResponse.status);

    // 对于非流式返回，直接获取并返回 JSON
    const responseData = await apiResponse.json();

    return new Response(JSON.stringify(responseData), {
      status: apiResponse.status,
      headers: {
        'Content-Type': 'application/json',
        'Access-Control-Allow-Origin': origin || '*',
        'Access-Control-Allow-Methods': 'POST, OPTIONS',
        'Access-Control-Allow-Headers': 'Content-Type, Authorization',
        'Access-Control-Max-Age': '86400'
      }
    });

  } catch (error) {
    console.error('Worker error:', error);
    return new Response(JSON.stringify({
      error: 'Internal server error',
      message: error.message
    }), {
      status: 500,
      headers: { 
        'Content-Type': 'application/json',
        'Access-Control-Allow-Origin': origin || '*'
      }
    });
  }
}

// 验证域名白名单
function isOriginAllowed(origin, referer) {
  if (origin && CONFIG.ALLOWED_ORIGINS.includes(origin)) {
    return true;
  }
  if (referer) {
    try {
      const refererUrl = new URL(referer);
      const refererOrigin = `${refererUrl.protocol}//${refererUrl.host}`;
      if (CONFIG.ALLOWED_ORIGINS.includes(refererOrigin)) {
        return true;
      }
    } catch (e) {
      // 解析失败忽略
    }
  }
  return false;
}

// 速率限制检查 (内存版)
function checkRateLimit(clientIP) {
  const now = Date.now();
  const key = `rate_${clientIP}`;

  if (!rateLimitMap.has(key)) {
    rateLimitMap.set(key, { count: 1, resetTime: now + CONFIG.RATE_LIMIT.windowMs });
    return true;
  }

  const rateData = rateLimitMap.get(key);

  if (now > rateData.resetTime) {
    rateLimitMap.set(key, { count: 1, resetTime: now + CONFIG.RATE_LIMIT.windowMs });
    return true;
  }

  if (rateData.count >= CONFIG.RATE_LIMIT.maxRequests) {
    return false;
  }

  rateData.count++;
  return true;
}

// 验证并格式化请求体
function validateAndFormatRequest(body) {
  // 必须包含 messages 数组
  if (!body.messages || !Array.isArray(body.messages)) {
    return false;
  }

  // 强制替换为你指定的阿里云模型名称
  body.model = CONFIG.TARGET_MODEL;

  // 限制 max_tokens 防滥用
  if (body.max_tokens && body.max_tokens > 4000) {
    body.max_tokens = 4000;
  }

  // 禁用流式输出（如果你在前端未处理流式响应 SSE 格式）
  // 如果前端需要支持流式，你可以移除这一行，但在 Worker 处理 Response 时需要支持流式转发
  body.stream = false; 

  return true;
}
