      const excludeTags = [
        "script",
        "style",
        "iframe",
        "embed",
        "video",
        "audio",
        "img",
        "svg",
      ];

      let textContent = "";

      // 尝试使用innerText作为备选方案，它比递归遍历更可靠
      if (element.innerText) {
