## 状态更新-setState

语法：数据的变化要更新UI视图，需要执行setState方法，setState方法会造成build的重新执行。

告诉 Flutter：数据变了，请重新调用 build() 刷新界面

例如我们写一个计数器

```dart
import 'package:flutter/material.dart';

void main() {
  runApp(MainPage());
}

class MainPage extends StatefulWidget {
  const MainPage({super.key});

  @override
  State<MainPage> createState() => _MainPageState();
}

class _MainPageState extends State<MainPage> {
  // 计数器
  int count = 0;

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: "终末地AI群聊",
      home: Scaffold(
        appBar: AppBar(centerTitle: true, title: Text("终末地AI群聊")),
        body: Center(
          //Row就是让这三个组件(即"减"+"数字"+"加"排成一条线)
          child: Row(
            children: [
              TextButton(
                onPressed: () {
                  count -= 1;
                  print(count);
                },
                child: Text("减"),
              ),
              //将count转换为字符串
              Text(count.toString()),
              //
              TextButton(
                onPressed: () {
                  count += 1;
                  print(count);
                },
                child: Text("加"),
              ),
            ],
          ),
        ),
        bottomNavigationBar: Container(
          height: 80,
          child: Center(child: Text("终末地AI群聊")),
        ),
      ),
    );
  }
}
```

此时我们发现点击加减号时中间的数字不会改变,这是因为我们没有添加setState状态监测

此时我们加上serState,然后点击加或者减就会看到中间的数字发生改变

```dart
import 'package:flutter/material.dart';

void main() {
  runApp(MainPage());
}

class MainPage extends StatefulWidget {
  const MainPage({super.key});

  @override
  State<MainPage> createState() => _MainPageState();
}

class _MainPageState extends State<MainPage> {
  // 计数器
  int count = 0;
  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: "终末地AI群聊",
      home: Scaffold(
        appBar: AppBar(centerTitle: true, title: Text("终末地AI群聊")),
        body: Center(
          child: Row( 
            children: [
              TextButton(
                onPressed: () {
                  //此时增加状态检测
                  setState(() {
                    count -= 1;
                    print(count);
                  });
                  //也可以这么写,因为这个是异步操作,setState为让程序重新执行build方法
                  //count -= 1;
                  //print(count);
                  //setState(() {});

                },
                child: Text("减"),
              ),
              Text(count.toString()),
              TextButton(
                onPressed: () {
                  //此时增加状态监测
                  setState(() {
                    count += 1;
                    print(count);
                  });
                  //也可以这么写
                  //count -= 1;
                  //print(count);
                  //setState(() {});
                },
                child: Text("加"),
              ),
            ],
          ),
        ),
        bottomNavigationBar: Container(
          height: 80,
          child: Center(child: Text("终末地AI群聊")),
        ),
      ),
    );
  }
}
