void main() {
  Map<String, int> map = {};

  // 添加键值对
  map['a'] = 1;           // 直接赋值
  map.putIfAbsent('b', () => 2);  // key不存在时才添加

  // 批量添加
  map.addAll({'c': 3, 'd': 4});

  // 修改值
