  // 更新（基于旧值）
  map.update('a', (v) => v * 2);           // 100 -> 200
  map.update('z', (v) => v * 2, ifAbsent: () => 0);  // 不存在则设为0

  print(map);  // {a: 200, b: 2, c: 3, d: 4, z: 0}
}
