  Map<String, int> m2 = {'b': 20, 'c': 3};  // b冲突

  // 展开合并（Dart 2.3+）
  Map<String, int> combined = {...m1, ...m2};  // m2的b覆盖m1的b
  print(combined);  // {a: 1, b: 20, c: 3}

  // 自定义合并（处理冲突）
  Map<String, int> merged = {};
  merged.addAll(m1);
  m2.forEach((k, v) {
    merged[k] = (merged[k] ?? 0) + v;  // 值相加
  });
  print(merged);  // {a: 1, b: 22, c: 3}

  // 条件展开
  bool useM2 = true;
  Map<String, int> conditional = {
    ...m1,
    if (useM2) ...m2,
  };
}
