## 第三版本

### server.js

```js
const express = require("express");
const http = require("http");
const { Server } = require("socket.io");
const axios = require("axios");

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: { origin: "*" },
});

// 👥 角色设置
const roles = {
  阿刀: "毒舌，喜欢怼人，说话很短",
  小白: "憨，经常问号",
  老哥: "爱玩梗，经常笑死、草",
};
const roleNames = Object.keys(roles);

// 📝 DeepSeek REST API 配置
const DEEPSEEK_API_KEY = "DeepseekAPI";
const DEEPSEEK_MODEL = "deepseek-chat";
const DEEPSEEK_URL = "https://api.deepseek.com/v1/chat/completions";

// 🧩 监听前端连接
io.on("connection", (socket) => {
  console.log("有人连接");

  socket.on("userMsg", async (msg) => {
    console.log("收到用户消息:", msg);

    // 1️⃣ 显示用户消息
    io.emit("msg", { name: "你", text: msg });

    // 2️⃣ 随机选一个角色回复
    const roleName = roleNames[Math.floor(Math.random() * roleNames.length)];

    // 3️⃣ 构造 Prompt
    const prompt = `
你是${roleName}
性格：${roles[roleName]}
你在QQ群聊天，风格要像真人
规则：
- 只说一句话
- 不超过15个字
- 不要解释
- 可以敷衍、吐槽、玩梗
- 不要像AI

用户说：
${msg}

你回复：
`;

    try {
      const response = await axios.post(
        DEEPSEEK_URL,
        {
          model: DEEPSEEK_MODEL,
          messages: [{ role: "user", content: prompt }],
        },
        {
          headers: {
            Authorization: `Bearer ${DEEPSEEK_API_KEY}`,
            "Content-Type": "application/json",
          },
          proxy: false, // 如果你在国内，可能需要设置代理
        },
      );

      console.log("原始返回数据:", response.data);

      const reply =
        response.data.choices[0]?.message?.content?.trim() || "AI没有返回内容";
      console.log("AI回复:", reply);

      io.emit("msg", { name: roleName, text: reply });
    } catch (err) {
      console.error("AI错误:", err.response ? err.response.data : err.message);
    }
  });
});

// ❌ 关闭自动水群，如果只想 AI 回答用户

server.listen(3000, () => {
  console.log("服务器运行：http://localhost:3000");
});

```

