## 第四版本

### server.js

```js
const express = require("express");
const http = require("http");
const { Server } = require("socket.io");
const axios = require("axios");
const fs = require("fs");

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: { origin: "*" },
});

// ================= 🌍 世界系统 =================
const world = {
  history: [],

  roles: {
    阿刀: {
      name: "阿刀",
      avatar: "https://api.dicebear.com/7.x/bottts/svg?seed=knife",
      personality: "毒舌，不耐烦",
      identity: "摆烂大学生，天天打游戏",
      style: "短句，阴阳怪气",
      memory: ["讨厌小白"],
      relationships: { 小白: -80, 老哥: 20 },
    },

    小白: {
      name: "小白",
      avatar: "https://api.dicebear.com/7.x/bottts/svg?seed=white",
      personality: "憨，经常问号",
      identity: "啥都不懂的萌新",
      style: "疑问句多",
      memory: ["经常被怼"],
      relationships: { 阿刀: -50 },
    },

    老哥: {
      name: "老哥",
      avatar: "https://api.dicebear.com/7.x/bottts/svg?seed=bro",
      personality: "爱玩梗",
      identity: "互联网老油条",
      style: "笑死 草 蚌埠住了",
      memory: [],
      relationships: {},
    },
  },
};

const roleNames = Object.keys(world.roles);

// ================= 🤖 DeepSeek =================
const API_KEY = "DeepseekAPI";
const URL = "https://api.deepseek.com/v1/chat/completions";

// ================= 🔧 工具函数 =================
function getRecentHistory() {
  return world.history
    .slice(-10)
    .map((m) => `${m.name}：${m.text}`)
    .join("\n");
}

function buildPrompt(role) {
  return `
你在QQ群聊天

你是${role.name}

身份：
${role.identity}

性格：
${role.personality}

说话风格：
${role.style}

记忆：
${role.memory.join("，")}

最近聊天：
${getRecentHistory()}

规则：
- 只说一句话
- 不超过15字
- 不要解释
- 像真人聊天
- 可以@别人

你说：
`;
}

async function aiReply(roleName) {
  const role = world.roles[roleName];

  const prompt = buildPrompt(role);

  try {
    const res = await axios.post(
      URL,
      {
        model: "deepseek-chat",
        messages: [{ role: "user", content: prompt }],
      },
      {
        headers: {
          Authorization: `Bearer ${API_KEY}`,
        },
      },
    );

    const text = res.data.choices[0].message.content.trim();

    const msg = {
      name: roleName,
      text,
      avatar: role.avatar,
    };

    world.history.push(msg);
    io.emit("msg", msg);
  } catch (e) {
    console.log("AI错误", e.message);
  }
}

// ================= 👥 用户消息 =================
io.on("connection", (socket) => {
  console.log("连接");

  socket.on("userMsg", async (msg) => {
    const userMsg = {
      name: "你",
      text: msg,
      avatar: "https://api.dicebear.com/7.x/bottts/svg?seed=user",
    };

    world.history.push(userMsg);
    io.emit("msg", userMsg);

    // 👉 多AI回应（关键）
    const count = Math.floor(Math.random() * 2) + 1;

    for (let i = 0; i < count; i++) {
      const roleName = roleNames[Math.floor(Math.random() * roleNames.length)];

      setTimeout(() => {
        aiReply(roleName);
      }, Math.random() * 3000);
    }
  });
});

// ================= 🤖 自动水群 =================
setInterval(() => {
  if (Math.random() < 0.5) return; // 有时候不说话

  const roleName = roleNames[Math.floor(Math.random() * roleNames.length)];

  aiReply(roleName);
}, 5000);

// ================= 💾 存档 =================
setInterval(() => {
  fs.writeFileSync("./chatlog.json", JSON.stringify(world, null, 2));
}, 10000);

// ================= 🚀 启动 =================
server.listen(3000, () => {
  console.log("http://localhost:3000");
});

