//- ========================================
//- 桌面宠物 - Hexo 主题内置插件 (Pug 模板)
//- ========================================

//- ========== CSS 样式 ==========
style.
  /* ===== 根容器 ===== */
  #pet-root {
    position: fixed;
    z-index: 99999;
    top: 0; left: 0;
    width: 0; height: 0;
    pointer-events: none;
    will-change: transform;
  }

  /* ===== 调试检测区域 ===== */
  #pet-debug-zone {
    position: absolute;
    display: none;
    pointer-events: none;
    border-radius: 4px;
    box-sizing: border-box;
  }

  /* ===== 内部容器 ===== */
  .pet-inner {
    position: absolute;
    top: 0; left: 0;
    transform-origin: top center;
    pointer-events: auto;
    cursor: grab;
    touch-action: none;
  }
  .pet-inner:active { cursor: grabbing; }

  /* ===== 精灵图 ===== */
  .pet-sprite {
    position: absolute;
    z-index: 40;
    top: 0; left: 0;
    width: 100%; height: 100%;
    background-repeat: no-repeat;
    background-size: contain;
    background-position: bottom center;
    image-rendering: pixelated;
    pointer-events: none;
  }

  /* ===== 头发画布 ===== */
  #pet-hair-canvas {
    position: absolute;
    z-index: 30;
    pointer-events: none;
    image-rendering: pixelated;
  }

  /* ===== 光环 ===== */
  .pet-halo {
    position: absolute;
    z-index: 20;
    pointer-events: none;
    image-rendering: pixelated;
  }

  /* ===== 影子 ===== */
  .pet-shadow {
    position: absolute;
    z-index: 1;
    pointer-events: none;
    image-rendering: pixelated;
  }

  /* ===== 汗水容器 ===== */
  #pet-sweat-container {
    position: absolute;
    z-index: 40;
    pointer-events: none;
    width: 0; height: 0;
  }

  /* ===== 烟雾容器 ===== */
  #pet-smoke-container {
    position: absolute;
    z-index: 5;
    pointer-events: none;
    width: 0; height: 0;
  }

  /* ===== 动画 ===== */
  @keyframes pet-sweat-anim {
    0%   { opacity: 0.4; transform: translate(0, 0) scale(0.5); }
    50%  { opacity: 0.4; transform: translate(var(--spread-x), var(--spread-y)) scale(1.2); }
