// 查找学生信息函数
void searchStudent(struct Student students[], int count) {

	//如果没有一个学生 
	if (count == 0) {
		printf("当前系统没有学生哦。\n");
		return;
	}

    int choice;
	printf("请选择查找方式：\n");
	printf("1. 按姓名查找\n");
	printf("2. 按学号查找\n");
	printf("请输入选项：");
	scanf("%d", &choice);

	switch (choice) {
	    case 1: { 
			// 按姓名查找
	        char name[30];
	        printf("请输入学生姓名：");
	        scanf("%s", name);
			//使用found来定义学生的存在状态 0不存在,1存在 
	        int found = 0;
	        for (int i = 0; i < count; i++) {
	        	//用strcmp将学生姓名一一对比,如果找到就跳出循环 
	            if (strcmp(students[i].name, name) == 0) {
	                printf("\n找到啦!\n");
	                printf("姓名：%s  学号：%lld  成绩：%.2f\n", students[i].name, students[i].id, students[i].score);
	                found = 1;
	                break;
	            }
	        }
	        //找不到就输出找不到 
	        if (!found) {
	            printf("没有找到该同学诶。\n");
	            break;
	        }
	        break;
	    }

	    case 2: { 
			// 按学号查找
	        int id;
	        printf("请输入学生学号：");
	        scanf("%d", &id);

	        int found = 0;

	        for (int i = 0; i < count; i++) {
	        	//和刚才的姓名查找逻辑一模一样,只是把结构体成员由name改为id 
	            if (students[i].id == id) {
	                printf("\n找到啦!\n");
	                printf("姓名：%s  学号：%lld  成绩：%.2f\n", students[i].name, students[i].id, students[i].score);
	                found = 1;
	                break;
	            }
	        }
	        //没找到就是没找到 
	        if (!found) {
	            printf("没有找到该同学诶。\n");
	            break;
	        }
	        break;
	    }
	    //如果不满足前两个case条件,就输出default 
	    default:
	        printf("无效的选项，您只能输入1或者2哦。\n");
	}
}


// 删除学生信息函数
void deleteStudent(struct Student students[], int *count) {
	//如果没有一个学生 
	if (*count == 0) {
		printf("当前系统没有学生哦。\n");
		return;
	}

  	int choice;
	printf("请选择删除方式：\n");
	printf("1. 按姓名删除\n");
	printf("2. 按学号删除\n");
	printf("请输入选项：");
	scanf("%d", &choice);
	//这里之所以让index=-1而不是0是因为还有一种情况,就是删除前先要通过姓名和学号来查找学生
	//如果输入了一个不存在的名字或学号,就要给出"找不到"的提示 
	//也就是说,前面的查找函数在这里又用了一下 
	int index = -1;
	switch (choice) {
	    case 1: { 
		// 按姓名删除
	        char name[30];
	        printf("请输入学生姓名：");
	        scanf("%s", name);
	  		//删除的逻辑和 上面查找函数一模一样,就是找到这个同学,然后删了他,只是定义了一个index=-1的区别 
	  		//因为如果定义index为0或者正数,就会影响下面for循环的使用 ,所以随便定义一个负数比如-1就可以了 
	        for (int i = 0; i < *count; i++) {
	            if (strcmp(students[i].name, name) == 0) {
	            	//找到了就将index改为当前的学生数组的索引 
	                index = i;
	                break;
	            }
	        }
	        //找不到就跳出 
	        break;
	    }


	    case 2: { 
		// 按学号删除
	        int id;
	        printf("请输入学生学号：");
	        scanf("%d", &id);
	  		//和姓名删除一模一样 
	        for (int i = 0; i < *count; i++) {
	            if (students[i].id == id) {
	                index = i;
	                break;
	            }
	        }
	        break;
	    }
	    //如果输入其他数字就提醒一下 
	    default:
	        printf("无效的选项，您只能输入1或者2哦。\n");
	        return;
	}
	//只要姓名和学号找不到,而代码在函数内从上往下执行 ,就一定会对index的值进行判断
	//然后提醒没有这个同学信息 
	if (index == -1) {
	    printf("没有找到该同学诶。\n");
	    return;
	}

	// 确认删除
	int confirm;
	for (int i = 0; i < 3; i++) {
		//为防止不小心删错了,所以用for循环搞一个确认三遍 
		// validInput用于检测输入是否有效,因为我发现输入0和1以外的数字会退出删除操作,所以强制规范一下 
	    int validInput = 0; 

		while (!validInput) {
		    printf("确定要删除该学生信息吗？需要您确认三遍才行哦(1. 确定 / 0. 取消)：");
		    if (scanf("%d", &confirm) == 1 && (confirm == 0 || confirm == 1)) {
		        validInput = 1; // 如果输入有效，就是要么是0,要么是1,就退出循环
		    } else {
		        printf("无效的输入，您只能输入0或者1哦\n");
		        while (getchar() != '\n');  // 清空输入缓冲区
		    }
		}
	    if (confirm != 1) {
	        printf("删除操作已取消。\n");
	        return;
	    }
	}

	// 删除学生信息
	//这里删除之后调整一下学生索引的位置 
	//就是继承原先数组学生的顺序,因为删了一个,新数组又少一个位子,所以被删的学生的索引位子会被下一个学生顶替 
	for (int i = index; i < *count - 1; i++) {
	    students[i] = students[i + 1];
	}
	//删除后将学生总数减一 
	(*count)--;
	printf("该同学信息已删除!\n");
}

// 修改学生信息函数
void modifyStudent(struct Student students[], int count) {
	//如果没有一个学生 
	if (count == 0) {
		printf("当前系统没有学生哦。\n");
		return;
